sequence.script:
var risk = {};
try {
    risk = mc.getPayloadJSON() || {};
} catch (e) {
    risk = {};
}
var decision = String(risk.decision || '').toUpperCase();
var downstreamStatus = Number(risk.status || 0);
if (downstreamStatus >= 400 || (decision !== 'ALLOW' && decision !== 'CHALLENGE' && decision !== 'DENY')) {
    decision = 'ERROR';
}
var score = Number(risk.riskScore || 0);
var partial = risk.partialResponse === true;
var reasons = Array.isArray(risk.reasons) ? risk.reasons : [];
var unavailable = Array.isArray(risk.unavailableServices) ? risk.unavailableServices : [];
mc.setProperty('risk.decision', decision);
mc.setProperty('risk.score', String(Number.isFinite(score) ? score : 0));
mc.setProperty('risk.partial', partial ? 'true' : 'false');
mc.setProperty('risk.reason.summary', reasons.join(','));
mc.setProperty('risk.unavailable.summary', unavailable.join(','));
mc.setProperty('risk.authorization.status',
    decision === 'ALLOW' ? 'AUTHORIZED' :
    decision === 'CHALLENGE' ? 'STEP_UP_REQUIRED' :
    decision === 'DENY' ? 'DENIED' : 'UNAVAILABLE');
